SELECT
FROM tb_pmb_internet_plan_list_new a LEFT OUTER JOIN tb_pmb_internet_mno b ON a.internet_mno_id = b.id WHERE 1=1
ORDER BY a.order_no LIMIT #{offset}, #{recordSize}

mapper.update:
UPDATE tb_pmb_internet_plan_list_new 
SET		
	prod_name                 	= #{prodName}
	,combination_name           = #{combinationName}
	,prod_descript		        = #{prodDescript}
	,internet_speed            	= #{internetSpeed}
	,tv_prod_name             	= #{tvProdName}
	,channel_count             	= #{channelCount}
	,combination_price         	= #{combinationPrice}
	,combination_freeble_price 	= #{combinationFreeblePrice}
	,order_no                   = #{orderNo}

		,use_yn                    	= #{useYn}

	,internet_mno_id           	= #{internetMnoId}			
	,modified_date             	= Now()
	,modified_id               	= #{modifiedId}
WHERE id = #{id}

update tb_pmb_internet_mno
SET 
	alam_rcv_num = #{alamRcvNum}
WHERE id = #{id}
